PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE lantern_news_submissions (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  body TEXT NOT NULL,
  actor_id TEXT,
  author_name TEXT NOT NULL,
  author_type TEXT NOT NULL DEFAULT 'student',
  image_r2_key TEXT,
  image_file_name TEXT,
  image_mime_type TEXT,
  image_file_size INTEGER,
  photo_credit TEXT,
  status TEXT NOT NULL DEFAULT 'pending',
  created_at TEXT NOT NULL,
  reviewed_at TEXT,
  reviewed_by_staff_id TEXT,
  reviewed_by_staff_name TEXT,
  decision_note TEXT
, video_r2_key TEXT, video_file_name TEXT, video_mime_type TEXT, video_file_size INTEGER, full_image_r2_key TEXT, link_url TEXT, hidden_at TEXT, hidden_by TEXT);
CREATE TABLE lantern_approvals (
  id TEXT PRIMARY KEY,
  item_type TEXT NOT NULL,
  item_id TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending',
  submitted_by_actor_id TEXT,
  submitted_by_actor_name TEXT,
  assigned_to_staff_id TEXT,
  assigned_to_staff_name TEXT,
  suggested_staff_id TEXT,
  suggested_staff_name TEXT,
  school_id TEXT,
  created_at TEXT NOT NULL,
  reviewed_at TEXT,
  reviewed_by_staff_id TEXT,
  reviewed_by_staff_name TEXT,
  decision_note TEXT
);
CREATE TABLE lantern_avatar_submissions (
  id TEXT PRIMARY KEY,
  character_name TEXT NOT NULL,
  image_key TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending',
  created_at TEXT NOT NULL,
  approved_at TEXT,
  approved_by TEXT,
  rejected_at TEXT,
  rejected_by TEXT,
  rejected_reason TEXT
);
CREATE TABLE lantern_avatar_profiles (
  character_name TEXT PRIMARY KEY,
  current_avatar_key TEXT NOT NULL,
  updated_at TEXT NOT NULL
);
CREATE TABLE lantern_wallets (
  character_name TEXT PRIMARY KEY,
  balance INTEGER NOT NULL DEFAULT 0,
  updated_at TEXT NOT NULL
);
CREATE TABLE lantern_transactions (
  id TEXT PRIMARY KEY,
  character_name TEXT NOT NULL,
  delta INTEGER NOT NULL,
  kind TEXT DEFAULT '',
  source TEXT DEFAULT '',
  note TEXT DEFAULT '',
  created_at TEXT NOT NULL,
  meta_json TEXT
);
CREATE TABLE lantern_teacher_recognition (
  id TEXT PRIMARY KEY,
  character_name TEXT NOT NULL,
  message TEXT NOT NULL,
  category TEXT,
  created_at TEXT NOT NULL,
  created_by_teacher_id TEXT,
  created_by_teacher_name TEXT
);
CREATE TABLE lantern_early_encourager_rewards (
  id TEXT PRIMARY KEY,
  character_name TEXT NOT NULL,
  item_type TEXT NOT NULL,
  item_id TEXT NOT NULL,
  rewarded_at TEXT NOT NULL
);
CREATE TABLE lantern_praise_preferences (
  character_name TEXT PRIMARY KEY,
  reaction_types TEXT NOT NULL,
  updated_at TEXT NOT NULL
);
CREATE TABLE lantern_missions (
  id TEXT PRIMARY KEY,
  teacher_id TEXT NOT NULL DEFAULT 'teacher',
  teacher_name TEXT NOT NULL DEFAULT 'Teacher',
  title TEXT NOT NULL,
  description TEXT NOT NULL DEFAULT '',
  reward_amount INTEGER NOT NULL DEFAULT 3,
  submission_type TEXT NOT NULL DEFAULT 'text',
  audience TEXT NOT NULL DEFAULT 'school_mission',
  target_character_names TEXT,
  featured INTEGER NOT NULL DEFAULT 0,
  active INTEGER NOT NULL DEFAULT 1,
  site_eligible INTEGER NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL
, allows_text INTEGER NOT NULL DEFAULT 1, allows_image INTEGER NOT NULL DEFAULT 0, allows_video INTEGER NOT NULL DEFAULT 0, allows_link INTEGER NOT NULL DEFAULT 0, min_characters INTEGER NOT NULL DEFAULT 200);
CREATE TABLE lantern_mission_submissions (
  id TEXT PRIMARY KEY,
  mission_id TEXT NOT NULL,
  character_name TEXT NOT NULL,
  submission_type TEXT NOT NULL DEFAULT 'text',
  submission_content TEXT NOT NULL DEFAULT '',
  status TEXT NOT NULL DEFAULT 'pending',
  created_at TEXT NOT NULL,
  reviewed_by TEXT,
  reviewed_at TEXT,
  returned_reason TEXT,
  returned_by TEXT,
  returned_at TEXT, hidden_at TEXT, hidden_by TEXT,
  FOREIGN KEY (mission_id) REFERENCES lantern_missions(id)
);
CREATE TABLE beta_reports (
  id TEXT PRIMARY KEY,
  created_at TEXT NOT NULL,
  reporter_name TEXT NOT NULL DEFAULT '',
  page TEXT NOT NULL DEFAULT 'Other',
  description TEXT NOT NULL DEFAULT '',
  screenshot_url TEXT
);
CREATE TABLE class_access_sessions (
  id TEXT PRIMARY KEY,
  teacher_id TEXT NOT NULL DEFAULT 'teacher',
  access_code TEXT NOT NULL,
  access_code_normalized TEXT NOT NULL,
  starts_at TEXT NOT NULL,
  expires_at TEXT NOT NULL,
  is_active INTEGER NOT NULL DEFAULT 1,
  revoked_at TEXT,
  created_at TEXT NOT NULL
);
CREATE TABLE class_access_tokens (
  id TEXT PRIMARY KEY,
  session_id TEXT NOT NULL,
  token TEXT NOT NULL UNIQUE,
  issued_at TEXT NOT NULL,
  expires_at TEXT NOT NULL,
  revoked_at TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (session_id) REFERENCES class_access_sessions(id)
);
CREATE TABLE lantern_verify_state (
  id TEXT PRIMARY KEY,
  state_json TEXT NOT NULL DEFAULT '{}',
  updated_at TEXT NOT NULL
);
CREATE TABLE lantern_test_students (   id TEXT PRIMARY KEY,   character_name TEXT NOT NULL UNIQUE,   display_name TEXT NOT NULL,   mode TEXT NOT NULL DEFAULT 'test',   created_at TEXT NOT NULL,   expires_at TEXT NOT NULL,   is_active INTEGER NOT NULL DEFAULT 1 );
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE lantern_poll_contributions (
  id TEXT PRIMARY KEY,
  character_name TEXT NOT NULL,
  question TEXT NOT NULL,
  choices_json TEXT NOT NULL,
  image_url TEXT,
  fallback_key TEXT,
  status TEXT NOT NULL DEFAULT 'pending',
  created_at TEXT NOT NULL,
  reviewed_at TEXT,
  reviewed_by TEXT,
  decision_note TEXT
);
CREATE TABLE lantern_polls (
  id TEXT PRIMARY KEY,
  mission_submission_id TEXT NOT NULL,
  question TEXT NOT NULL,
  choices_json TEXT NOT NULL,
  created_by_character TEXT NOT NULL,
  created_at TEXT NOT NULL,
  approved_at TEXT
, image_url TEXT, character_name TEXT NOT NULL DEFAULT '');
CREATE TABLE lantern_poll_votes (
  id TEXT PRIMARY KEY,
  poll_id TEXT NOT NULL,
  character_name TEXT NOT NULL,
  choice_index INTEGER NOT NULL,
  created_at TEXT NOT NULL,
  UNIQUE(poll_id, character_name),
  FOREIGN KEY (poll_id) REFERENCES lantern_polls(id)
);
CREATE TABLE lantern_poll_voter_rewards (
  id TEXT PRIMARY KEY,
  poll_id TEXT NOT NULL,
  character_name TEXT NOT NULL,
  created_at TEXT NOT NULL,
  UNIQUE(poll_id, character_name)
);
CREATE TABLE lantern_reactions (id TEXT PRIMARY KEY, item_type TEXT NOT NULL, item_id TEXT NOT NULL, reaction_type TEXT NOT NULL, character_name TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE lantern_bug_reports (id TEXT PRIMARY KEY, character_name TEXT NOT NULL, description TEXT NOT NULL, image_url TEXT, status TEXT NOT NULL DEFAULT 'approved', created_at TEXT NOT NULL);
CREATE TABLE lantern_leaderboard_entries (id TEXT PRIMARY KEY, game_name TEXT NOT NULL, character_name TEXT NOT NULL, score INTEGER NOT NULL, score_display TEXT, meta_json TEXT, created_at TEXT NOT NULL);
CREATE TABLE lantern_media_library (id TEXT PRIMARY KEY, category TEXT NOT NULL, image_key TEXT NOT NULL, sort_order INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL);
CREATE TABLE lantern_content_flags (id TEXT PRIMARY KEY, item_type TEXT NOT NULL, item_id TEXT NOT NULL, reported_by TEXT NOT NULL, reason TEXT, created_at TEXT NOT NULL);
CREATE TABLE lantern_setup_state (
  id TEXT PRIMARY KEY,
  setup_completed_at TEXT,
  updated_at TEXT NOT NULL
);
CREATE TABLE lantern_pilot_accounts (
  username TEXT PRIMARY KEY,
  display_name TEXT NOT NULL,
  role TEXT NOT NULL CHECK (role IN ('student', 'teacher', 'admin')),
  password_hash TEXT,
  password_salt TEXT,
  student_character_name TEXT,
  teacher_id TEXT,
  updated_at TEXT NOT NULL
, is_active INTEGER DEFAULT 1, student_must_change_password INTEGER NOT NULL DEFAULT 0, must_change_password INTEGER NOT NULL DEFAULT 0, password_changed_at TEXT, password_reset_at TEXT, password_reset_by TEXT, mtss_student_id TEXT);
CREATE TABLE lantern_student_identities (
  character_name TEXT PRIMARY KEY,
  display_name TEXT,
  created_at TEXT NOT NULL
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_lantern_news_submissions_actor ON lantern_news_submissions(actor_id);
CREATE INDEX idx_lantern_news_submissions_status ON lantern_news_submissions(status);
CREATE INDEX idx_lantern_news_submissions_created ON lantern_news_submissions(created_at);
CREATE INDEX idx_lantern_approvals_item ON lantern_approvals(item_type, item_id);
CREATE INDEX idx_lantern_approvals_status ON lantern_approvals(status);
CREATE INDEX idx_lantern_approvals_assigned ON lantern_approvals(assigned_to_staff_id);
CREATE INDEX idx_lantern_approvals_suggested ON lantern_approvals(suggested_staff_id);
CREATE INDEX idx_lantern_approvals_created ON lantern_approvals(created_at);
CREATE INDEX idx_lantern_avatar_submissions_character ON lantern_avatar_submissions(character_name);
CREATE INDEX idx_lantern_avatar_submissions_status ON lantern_avatar_submissions(status);
CREATE INDEX idx_lantern_transactions_character ON lantern_transactions(character_name);
CREATE INDEX idx_lantern_transactions_created ON lantern_transactions(created_at);
CREATE INDEX idx_lantern_teacher_recognition_character ON lantern_teacher_recognition(character_name);
CREATE INDEX idx_lantern_teacher_recognition_created ON lantern_teacher_recognition(created_at);
CREATE UNIQUE INDEX idx_lantern_early_encourager_char_item
  ON lantern_early_encourager_rewards(character_name, item_type, item_id);
CREATE INDEX idx_lantern_early_encourager_char_date
  ON lantern_early_encourager_rewards(character_name, rewarded_at);
CREATE INDEX idx_lantern_missions_teacher ON lantern_missions(teacher_id);
CREATE INDEX idx_lantern_missions_active ON lantern_missions(active);
CREATE INDEX idx_lantern_missions_created ON lantern_missions(created_at);
CREATE INDEX idx_lantern_mission_submissions_mission ON lantern_mission_submissions(mission_id);
CREATE INDEX idx_lantern_mission_submissions_character ON lantern_mission_submissions(character_name);
CREATE INDEX idx_lantern_mission_submissions_status ON lantern_mission_submissions(status);
CREATE INDEX idx_lantern_mission_submissions_created ON lantern_mission_submissions(created_at);
CREATE INDEX idx_beta_reports_created ON beta_reports(created_at);
CREATE INDEX idx_class_access_sessions_teacher ON class_access_sessions(teacher_id);
CREATE INDEX idx_class_access_sessions_active_expires ON class_access_sessions(is_active, expires_at);
CREATE INDEX idx_class_access_sessions_code_norm ON class_access_sessions(access_code_normalized);
CREATE INDEX idx_class_access_tokens_session ON class_access_tokens(session_id);
CREATE INDEX idx_class_access_tokens_token ON class_access_tokens(token);
CREATE INDEX idx_class_access_tokens_expires ON class_access_tokens(expires_at);
CREATE INDEX idx_test_students_expires ON lantern_test_students (expires_at);
CREATE INDEX idx_test_students_character ON lantern_test_students (character_name);
CREATE INDEX idx_poll_contrib_status ON lantern_poll_contributions(status);
CREATE INDEX idx_lantern_polls_approved ON lantern_polls(approved_at);
CREATE INDEX idx_poll_votes_poll ON lantern_poll_votes(poll_id);
CREATE INDEX idx_poll_votes_character ON lantern_poll_votes(character_name);
CREATE INDEX idx_poll_voter_rewards_poll ON lantern_poll_voter_rewards(poll_id);
CREATE UNIQUE INDEX idx_lantern_reactions_unique ON lantern_reactions(item_type, item_id, reaction_type, character_name);
CREATE INDEX idx_lantern_reactions_item ON lantern_reactions(item_type, item_id);
CREATE INDEX idx_lantern_reactions_character ON lantern_reactions(character_name);
CREATE INDEX idx_bug_reports_created ON lantern_bug_reports(created_at);
CREATE INDEX idx_leaderboard_game_created ON lantern_leaderboard_entries(game_name, created_at);
CREATE INDEX idx_leaderboard_character ON lantern_leaderboard_entries(character_name);
CREATE INDEX idx_media_library_category ON lantern_media_library(category);
CREATE INDEX idx_lantern_content_flags_item ON lantern_content_flags(item_type, item_id);
CREATE INDEX idx_lantern_content_flags_created ON lantern_content_flags(created_at);
CREATE INDEX idx_lantern_pilot_accounts_role ON lantern_pilot_accounts(role);
